# === SAFER: restricted unpickler ===
import io
import pickletools

class SafeUnpickler(pickle.Unpickler):
    ALLOWED_CLASSES = {
        'builtins.dict', 'builtins.list', 'builtins.str',
        'builtins.int', 'builtins.float', 'builtins.bytes',
        'collections.OrderedDict',
    }

    def find_class(self, module, name):
        qualified = f'{module}.{name}'
        if qualified not in self.ALLOWED_CLASSES:
            raise pickle.UnpicklingError(f'forbidden class: {qualified}')
        return super().find_class(module, name)

def safe_load(data: bytes):
    return SafeUnpickler(io.BytesIO(data)).load()

